namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public string ImageEmoji { get; set; } = "🍽️";
    public int TotalRatings { get; set; }
    public int RatingSum { get; set; }
    public double AverageRating => TotalRatings > 0 ? (double)RatingSum / TotalRatings : 0;
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Emoji { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Description = "A simple, classic pizza with fresh mozzarella and basil.",
                ImageEmoji = "🍕",
                Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
                Steps = ["Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
                TotalRatings = 12, RatingSum = 52
            },
            new Recipe
            {
                Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
                Description = "Creamy egg-based pasta with crispy pancetta.",
                ImageEmoji = "🍝",
                Ingredients = ["400g spaghetti", "200g pancetta", "4 egg yolks", "100g Pecorino Romano", "Black pepper"],
                Steps = ["Cook spaghetti in salted boiling water.", "Fry pancetta until crispy.", "Whisk egg yolks with grated Pecorino and pepper.", "Drain pasta, reserving 1 cup of pasta water.", "Toss hot pasta with pancetta, then quickly stir in egg mixture.", "Add pasta water as needed for a creamy consistency."],
                TotalRatings = 8, RatingSum = 38
            },
            new Recipe
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Description = "Tender chicken in a rich, spiced tomato-cream sauce.",
                ImageEmoji = "🍛",
                Ingredients = ["500g chicken breast", "1 cup yogurt", "2 tbsp garam masala", "Canned tomatoes", "Heavy cream", "Onion", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices for 1 hour.", "Grill or pan-sear chicken until charred.", "Sauté onion, garlic, and ginger until soft.", "Add tomatoes and simmer for 15 minutes.", "Stir in cream and add the chicken.", "Simmer for 10 minutes and serve with rice."],
                TotalRatings = 15, RatingSum = 70
            },
            new Recipe
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Description = "Sweet, sour, and savory stir-fried rice noodles.",
                ImageEmoji = "🥡",
                Ingredients = ["200g rice noodles", "2 eggs", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Sugar", "Tofu"],
                Steps = ["Soak rice noodles in warm water for 30 minutes.", "Mix tamarind paste, fish sauce, and sugar for the sauce.", "Stir-fry tofu until golden, set aside.", "Scramble eggs in the wok.", "Add noodles and sauce, toss until coated.", "Top with bean sprouts, peanuts, and lime wedges."],
                TotalRatings = 6, RatingSum = 26
            },
            new Recipe
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
                ImageEmoji = "🌮",
                Ingredients = ["500g ground beef", "Taco seasoning", "Corn tortillas", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Salsa"],
                Steps = ["Brown the ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm tortillas in a dry pan.", "Fill tortillas with seasoned beef.", "Top with lettuce, tomato, cheese, sour cream, and salsa.", "Serve immediately with lime wedges."],
                TotalRatings = 10, RatingSum = 43
            },
            new Recipe
            {
                Id = 6, Title = "Guacamole", Category = "Mexican",
                Description = "Fresh, creamy avocado dip with lime and cilantro.",
                ImageEmoji = "🥑",
                Ingredients = ["3 ripe avocados", "1 lime", "1/2 red onion", "Cilantro", "Jalapeño", "Salt", "Tomato"],
                Steps = ["Halve avocados and scoop into a bowl.", "Mash to desired consistency.", "Add diced onion, tomato, and jalapeño.", "Squeeze in lime juice.", "Chop and fold in cilantro.", "Season with salt and serve with tortilla chips."],
                TotalRatings = 9, RatingSum = 40
            },
            new Recipe
            {
                Id = 7, Title = "Miso Soup", Category = "Asian",
                Description = "A warm, savory Japanese soup with tofu and seaweed.",
                ImageEmoji = "🍜",
                Ingredients = ["4 cups dashi stock", "3 tbsp miso paste", "Silken tofu", "Wakame seaweed", "Green onions"],
                Steps = ["Heat dashi stock until simmering.", "Cube tofu and rehydrate wakame.", "Add tofu and wakame to the stock.", "Remove from heat and dissolve miso paste into the broth.", "Ladle into bowls.", "Garnish with sliced green onions."],
                TotalRatings = 5, RatingSum = 21
            },
            new Recipe
            {
                Id = 8, Title = "Butter Chicken", Category = "Indian",
                Description = "Creamy, mildly spiced tomato-butter chicken curry.",
                ImageEmoji = "🍗",
                Ingredients = ["500g chicken thighs", "Butter", "Canned tomatoes", "Heavy cream", "Garam masala", "Cumin", "Garlic", "Ginger"],
                Steps = ["Marinate chicken in yogurt and spices.", "Sear chicken in butter until browned.", "Blend tomatoes and cook down with spices.", "Add cream and butter to the sauce.", "Add chicken and simmer for 20 minutes.", "Serve with naan bread or basmati rice."],
                TotalRatings = 11, RatingSum = 49
            },
        ];
        _nextId = 9;
    }

    public List<RecipeCategory> GetCategories()
    {
        return
        [
            new RecipeCategory { Name = "Italian", Emoji = "🇮🇹", Description = "Pasta, pizza, and Mediterranean classics" },
            new RecipeCategory { Name = "Mexican", Emoji = "🇲🇽", Description = "Bold flavors with fresh salsas and tortillas" },
            new RecipeCategory { Name = "Indian", Emoji = "🇮🇳", Description = "Rich curries and aromatic spice blends" },
            new RecipeCategory { Name = "Asian", Emoji = "🌏", Description = "Stir-fries, noodles, and umami-packed dishes" },
        ];
    }

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.TotalRatings++;
            recipe.RatingSum += stars;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }
}

@using RecipeShare.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _displayStars ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => _hoverStars = star"
              @onmouseout="() => _hoverStars = 0"
              role="button"
              title="Rate @star stars">
            ★
        </span>
    }
    <span class="rating-info">
        @if (_submitted)
        {
            <span class="text-success">✓ Thanks!</span>
        }
        @if (AverageRating > 0)
        {
            <span>@AverageRating.ToString("0.0") avg (@TotalRatings ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int _hoverStars;
    private int _selectedStars;
    private bool _submitted;

    private int _displayStars => _hoverStars > 0 ? _hoverStars : _selectedStars;

    private void SubmitRating(int stars)
    {
        if (_submitted) return;
        _selectedStars = stars;
        _submitted = true;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
    }
}

.star-rating {
    display: flex;
    align-items: center;
    gap: 2px;
}

.star {
    font-size: 1.8rem;
    color: #ccc;
    cursor: pointer;
    transition: color 0.15s, transform 0.15s;
    user-select: none;
}

.star:hover {
    transform: scale(1.2);
}

.star.filled {
    color: #f5a623;
}

.rating-info {
    margin-left: 0.75rem;
    font-size: 0.9rem;
    color: #666;
    display: flex;
    gap: 0.5rem;
}

