{"path": "/tmp/sv-78a709d35da841c98dba2b1963656bd0/RecipeShare/Components/StarRating.razor", "file_text": "@using RecipeShare.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _displayStars ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => _hoverStars = star"
              @onmouseout="() => _hoverStars = 0"
              role="button"
              title="Rate @star stars">
            ★
        </span>
    }
    <span class="rating-info">
        @if (_submitted)
        {
            <span class="text-success">✓ Thanks!</span>
        }
        @if (AverageRating > 0)
        {
            <span>@AverageRating.ToString("0.0") avg (@TotalRatings ratings)</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int _hoverStars;
    private int _selectedStars;
    private bool _submitted;

    private int _displayStars => _hoverStars > 0 ? _hoverStars : _selectedStars;

    private void SubmitRating(int stars)
    {
        if (_submitted) return;
        _selectedStars = stars;
        _submitted = true;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            AverageRating = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
    }
}
"}

