@page "/category/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <div class="d-flex align-items-center mb-2">
                            <span style="font-size: 2rem;" class="me-2">@recipe.ImageEmoji</span>
                            <h4 class="card-title mb-0">@recipe.Title</h4>
                        </div>
                        <p class="card-text text-muted">@recipe.Description</p>
                        @if (recipe.TotalRatings > 0)
                        {
                            <small class="text-warning">
                                @for (int i = 0; i < (int)Math.Round(recipe.AverageRating); i++) { <text>★</text> }
                                <span class="text-muted">(@recipe.AverageRating.ToString("0.0"))</span>
                            </small>
                        }
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe →</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    private List<RecipeShare.Models.Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

