{"file_text": "@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Services
@using RecipeShare.Models
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

<EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" @bind-Value="_model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => _model.Title" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" @bind-Value="_model.Category" class="form-select">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat.Name">@cat.Emoji @cat.Name</option>
            }
        </InputSelect>
        <ValidationMessage For="() => _model.Category" class="text-danger" />
    </div>

    <div class="mb-3">
        <label for="description" class="form-label">Short Description</label>
        <InputTextArea id="description" @bind-Value="_model.Description" class="form-control" rows="2"
                       placeholder="A brief description of the dish" />
    </div>

    <div class="mb-3">
        <label class="form-label">Ingredients (one per line)</label>
        <InputTextArea @bind-Value="_model.IngredientsText" class="form-control" rows="5"
                       placeholder="200g flour&#10;3 eggs&#10;1 cup sugar" />
        <ValidationMessage For="() => _model.IngredientsText" class="text-danger" />
    </div>

    <div class="mb-3">
        <label class="form-label">Steps (one per line)</label>
        <InputTextArea @bind-Value="_model.StepsText" class="form-control" rows="5"
                       placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
        <ValidationMessage For="() => _model.StepsText" class="text-danger" />
    </div>

    <button type="submit" class="btn btn-success btn-lg">🚀 Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel _model = new();

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Description = _model.Description,
            Ingredients = _model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = _model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            ImageEmoji = "🍽️"
        };

        RecipeService.AddRecipe(recipe);
        Navigation.NavigateTo($"recipe/{recipe.Id}");
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please enter a recipe title.")]
        [System.ComponentModel.DataAnnotations.StringLength(100)]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        public string Description { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string StepsText { get; set; } = string.Empty;
    }
}
